#include <bits/stdc++.h>
using namespace std;
#define int long long

//由于 a 的长度小于等于 10，需要 long long

int n,m,cnt=1;

//初始码力为 1

int ans,v;
signed main(){
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m;
	vector<int> a(n+5);
	for(int i=1;i<=n;i++){
		cin>>a[i];
		int x=ans;
		cnt+=a[i];
		//累加 a[i]
		ans=max(ans,cnt);
		if(x!=ans){
			//确定是否取到更大值
			v=i;
			//确定最大值编号
		}
	}
	ans<<=m;
	//最大值得到后，吃掉所有金苹果
	for(int i=v+1;i<=n;i++){
		ans+=a[i];
	}
	//得到最大值并翻倍后，吃掉剩下的红苹果
	cout<<ans;
	return 0;
}
